// keys emit sync_warning and are skipped without aborting the run, so
// sync still completes for resources that DO have resolvable paths.
var unresolvedPathKeyRE = regexp.MustCompile(`\{[a-zA-Z_][a-zA-Z0-9_]*\}`)

